#!/usr/bin/env node

/**
 * View 2: Parse Claude Code session token usage.
 *
 * Primary path: reads from summary.json (generated by run.py).
 * Fallback path: parses raw JSONL files directly (for older runs).
 *
 * Usage:
 *   node benchmark/parse-sessions.mjs \
 *     --label "notion-agent-cli" session1.jsonl \
 *     --label "MCP" session2.jsonl
 *
 *   node benchmark/parse-sessions.mjs --summary benchmark/results/<run-id>/summary.json
 *
 * Reports per session:
 *   - input_tokens (total processed)
 *   - cache_read_input_tokens
 *   - cache_creation_input_tokens
 *   - billed_input_tokens ≈ input_tokens - cache_read_input_tokens
 *   - output_tokens
 *   - turns count
 */

import { readFileSync, existsSync } from "node:fs";
import { dirname, resolve } from "node:path";

// ── Arg parsing ──────────────────────────────────────────────────────────────

function parseArgs(argv) {
  const args = argv.slice(2);
  const sessions = [];
  let currentLabel = null;
  let summaryPath = null;

  for (let i = 0; i < args.length; i++) {
    if (args[i] === "--label") {
      currentLabel = args[++i];
    } else if (args[i] === "--summary") {
      summaryPath = args[++i];
    } else if (args[i].startsWith("--")) {
      process.stderr.write(`Unknown option: ${args[i]}\n`);
      process.exit(1);
    } else {
      // File path
      sessions.push({
        label: currentLabel || `session-${sessions.length + 1}`,
        file: args[i],
      });
      currentLabel = null;
    }
  }

  if (!summaryPath && sessions.length === 0) {
    process.stderr.write(
      "Usage: node benchmark/parse-sessions.mjs --label <name> <file.jsonl> ...\n" +
        "       node benchmark/parse-sessions.mjs --summary <summary.json>\n",
    );
    process.exit(1);
  }

  return { sessions, summaryPath };
}

// ── Summary.json reader ─────────────────────────────────────────────────────

function loadFromSummary(summaryPath) {
  const data = JSON.parse(readFileSync(summaryPath, "utf-8"));
  return data.sessions.map((s) => ({
    label: s.label,
    totalProcessed: s.input_tokens + s.cache_read_tokens + s.cache_creation_tokens,
    totalInputTokens: s.input_tokens,
    totalOutputTokens: s.output_tokens,
    totalCacheRead: s.cache_read_tokens,
    totalCacheCreation: s.cache_creation_tokens,
    billedInputTokens: s.input_tokens + s.cache_creation_tokens,
    turns: s.num_turns,
  }));
}

// ── JSONL Parser (fallback) ─────────────────────────────────────────────────

/**
 * Parse a Claude Code session JSONL file and extract token usage.
 */
function parseSessionFile(filePath) {
  const content = readFileSync(filePath, "utf-8");
  const lines = content
    .trim()
    .split("\n")
    .filter((l) => l.trim());

  let totalInputTokens = 0;
  let totalOutputTokens = 0;
  let totalCacheRead = 0;
  let totalCacheCreation = 0;
  let turns = 0;

  for (const line of lines) {
    let entry;
    try {
      entry = JSON.parse(line);
    } catch {
      continue;
    }

    const usage = entry?.message?.usage || entry?.usage || entry?.response?.usage;
    if (!usage) continue;

    const inputTk = usage.input_tokens || 0;
    const outputTk = usage.output_tokens || 0;
    const cacheRead = usage.cache_read_input_tokens || 0;
    const cacheCreation = usage.cache_creation_input_tokens || 0;

    if (entry?.type === "assistant" || inputTk > 0 || outputTk > 0 || cacheRead > 0 || cacheCreation > 0) {
      totalInputTokens += inputTk;
      totalOutputTokens += outputTk;
      totalCacheRead += cacheRead;
      totalCacheCreation += cacheCreation;
      turns++;
    }
  }

  const totalProcessed = totalInputTokens + totalCacheRead + totalCacheCreation;
  const billedInputTokens = totalInputTokens + totalCacheCreation;

  return {
    totalProcessed,
    totalInputTokens,
    totalOutputTokens,
    totalCacheRead,
    totalCacheCreation,
    billedInputTokens,
    turns,
  };
}

// ── Reporting ────────────────────────────────────────────────────────────────

function padRight(str, len) {
  return String(str).padEnd(len);
}

function padLeft(str, len) {
  return String(str).padStart(len);
}

function fmt(n) {
  return n.toLocaleString("en-US");
}

function printReport(labels, results) {
  const colWidth = 22;
  const metricWidth = 34;

  console.log(`\n${"═".repeat(metricWidth + labels.length * colWidth)}`);
  console.log("  View 2: Claude Code Session Token Analysis");
  console.log(`${"═".repeat(metricWidth + labels.length * colWidth)}`);

  console.log(padRight("Metric", metricWidth) + labels.map((l) => padLeft(l, colWidth)).join(""));
  console.log("─".repeat(metricWidth + labels.length * colWidth));

  const metrics = [
    ["Total context (in+cache)", "totalProcessed"],
    ["New input tokens", "totalInputTokens"],
    ["Cache read tokens (75% off)", "totalCacheRead"],
    ["Cache creation tokens", "totalCacheCreation"],
    ["Billed input (new+creation)", "billedInputTokens"],
    ["Output tokens", "totalOutputTokens"],
    ["Turns", "turns"],
  ];

  for (const [label, key] of metrics) {
    let row = padRight(label, metricWidth);
    for (const r of results) {
      row += padLeft(fmt(r[key]), colWidth);
    }
    console.log(row);
  }

  console.log();
}

// ── Main ─────────────────────────────────────────────────────────────────────

function main() {
  const { sessions, summaryPath } = parseArgs(process.argv);

  if (summaryPath) {
    // Primary path: read from summary.json
    process.stderr.write(`Reading from ${summaryPath}...\n`);
    const results = loadFromSummary(summaryPath);
    const labels = results.map((r) => r.label);
    printReport(labels, results);
    console.log(JSON.stringify(results, null, 2));
    return;
  }

  // Check if any session file sits next to a summary.json
  if (sessions.length > 0) {
    const dir = dirname(resolve(sessions[0].file));
    const summaryFile = resolve(dir, "summary.json");
    if (existsSync(summaryFile)) {
      process.stderr.write(`Found summary.json, reading from ${summaryFile}...\n`);
      const results = loadFromSummary(summaryFile);
      const labels = results.map((r) => r.label);
      printReport(labels, results);
      console.log(JSON.stringify(results, null, 2));
      return;
    }
  }

  // Fallback: parse raw JSONL files
  const results = [];
  for (const session of sessions) {
    process.stderr.write(`Parsing ${session.file} (${session.label})...\n`);
    const result = parseSessionFile(session.file);
    results.push(result);
    process.stderr.write(`  ${result.turns} turns, ${fmt(result.totalInputTokens)} input tokens\n`);
  }

  const labels = sessions.map((s) => s.label);
  printReport(labels, results);

  const jsonOutput = sessions.map((s, i) => ({
    label: s.label,
    file: s.file,
    ...results[i],
  }));
  console.log(JSON.stringify(jsonOutput, null, 2));
}

main();
